// 1. Pegue o texto que o OpenRouter gerou. 
// ATENÇÃO: Mude o ".text" abaixo para o nome exato do campo que o seu nó do OpenRouter está retornando (pode ser .message ou .content)
let respostaIA = $input.item.json.text; 

// 2. Limpa qualquer formatação de markdown (crases) caso a IA seja teimosa
let textoLimpo = respostaIA.replace(/```json/gi, '').replace(/```/gi, '').trim();

// 3. Converte a string limpa em um objeto JSON real
let dadosConvertidos = JSON.parse(textoLimpo);

// 4. Retorna o objeto puro para o n8n
return dadosConvertidos.items;

// Inicializamos as variáveis para somar os totais
let totalCalorias = 0;
let totalProteinas = 0;
let totalCarboidratos = 0;
let totalGorduras = 0;

// Variável para guardar a lista de alimentos formatada
let detalhesAlimentos = "";

// Pegamos todos os itens devolvidos pelo nó do PostgreSQL
const itens = $input.all();

// O loop varre cada alimento retornado pelo banco
for (const item of itens) {
    const dados = item.json;

    // Se por acaso a IA inventar um alimento que não existe na TACO e voltar nulo
    if (!dados.descri_o_dos_alimentos) {
        detalhesAlimentos += `❓ _Alimento não identificado_\n`;
        continue;
    }

    // Limpa um pouco o nome para não ficar gigante (opcional, pega até a primeira vírgula)
    // Ex: "Frango, peito, sem pele" vira "Frango" - Se quiser o nome completo, troque para: const nome = dados.descri_o_dos_alimentos;
    const nome = dados.descri_o_dos_alimentos; 

    // Garantimos que são números e tratamos casos nulos
    const cal = Number(dados.calorias_kcal) || 0;
    const prot = Number(dados.proteina_g) || 0;
    const carb = Number(dados.carboidratos_g) || 0;
    const gord = Number(dados.gorduras_g) || 0;

    // Somamos aos totais
    totalCalorias += cal;
    totalProteinas += prot;
    totalCarboidratos += carb;
    totalGorduras += gord;

    // Montamos a linha deste alimento com formatação do WhatsApp (*negrito*, _itálico_)
    detalhesAlimentos += `🔹 *${nome.trim()}*: ${cal.toFixed(1)} kcal\n`;
    detalhesAlimentos += `    _P: ${prot.toFixed(1)}g | C: ${carb.toFixed(1)}g | G: ${gord.toFixed(1)}g_\n\n`;
}

// Montamos a mensagem final juntando tudo
let mensagemFinal = `🍽️ *Resumo da sua Refeição* 🍽️\n\n`;
mensagemFinal += `*O que você consumiu:*\n${detalhesAlimentos}`;
mensagemFinal += `━━━━━━━━━━━━━━━━━\n`;
mensagemFinal += `📊 *TOTAIS DA REFEIÇÃO*\n`;
mensagemFinal += `🔥 Calorias: *${totalCalorias.toFixed(1)} kcal*\n`;
mensagemFinal += `🍗 Proteínas: *${totalProteinas.toFixed(1)}g*\n`;
mensagemFinal += `🍞 Carboidratos: *${totalCarboidratos.toFixed(1)}g*\n`;
mensagemFinal += `🥑 Gorduras: *${totalGorduras.toFixed(1)}g*\n`;

// Retornamos a mensagem pronta dentro de uma propriedade chamada "mensagem_whatsapp"
return [{ 
    json: { 
        mensagem_whatsapp: mensagemFinal,
        dados_brutos: {
            kcal: totalCalorias,
            p: totalProteinas,
            c: totalCarboidratos,
            g: totalGorduras
        }
    } 
}];

const inputData = $input.all();

const alimentos = inputData.map((item, index) => {
  const data = item.json;

  let quantidade = 100.00;

  try {
    const jsonCorrespondente = $("converto_json").itemMatching(index);

    if (jsonCorrespondente && jsonCorrespondente.json.quantity_g) {
      quantidade = parseFloat(jsonCorrespondente.json.quantity_g);
    }
  } catch (error) {
    console.log("Não foi possível parear via itemMatching, usando fallback.");
  }

  return {
    tabelaNutricionalId: Number(data.n_mero_do_alimento) || 0, 
    gordura: parseFloat(data.gorduras_g) || 0.0,
    proteina: parseFloat(data.proteina_g) || 0.0,
    carboidrato: parseFloat(data.carboidratos_g) || 0.0,
    calorias: parseFloat(data.calorias_kcal) || 0.0,
    quantidadeConsumida: quantidade,
    fotoEnviadaUrl: null
  };
});

const idUsuario = $("busca_usuario").first().json.id;
const dataAtual = new Date();
dataAtual.setTime(dataAtual.getTime() - (3 * 60 * 60 * 1000));
const dataFormatada = dataAtual.getFullYear() + '-' +
  String(dataAtual.getMonth() + 1).padStart(2, '0') + '-' +
  String(dataAtual.getDate()).padStart(2, '0') + 'T' +
  String(dataAtual.getHours()).padStart(2, '0') + ':' +
  String(dataAtual.getMinutes()).padStart(2, '0') + ':' +
  String(dataAtual.getSeconds()).padStart(2, '0');

const jsonFinal = {
  dataHoraConsumo: dataFormatada,
  usuarioId: Number(idUsuario) || 0,
  alimentos: alimentos
};

return [{ json: jsonFinal }];
